   "source": [
    "library(tidyverse)      # Data manipulation and ggplot2\n",
    "library(lubridate)      # Date handling\n",
    "library(tsibble)        # Time series tibbles\n",
    "library(feasts)         # STL decomposition\n",
    "library(sandwich)       # Newey-West robust standard errors\n",
    "library(lmtest)         # coeftest\n",
    "library(car)            # VIF\n",
    "library(strucchange)    # Structural break tests\n",
    "library(forecast)       # ARIMA/ARIMAX\n",
    "library(rugarch)        # GARCH models\n",
    "library(zoo)            # na.approx for interpolation\n",
    "library(gridExtra)      # Arranging multiple plots\n",
    "library(moments)        # skewness, kurtosis\n",
    "# For reproducibility\n",
    "set.seed(2024)"
   ]
  },
