   "source": [
    " 2. Data Simulation "
   ]
  },
  {
   "cell_type": "code",
   "execution_count": 2,
   "id": "e39bf336",
   "metadata": {
    "execution": {
     "iopub.execute_input": "2026-03-06T11:31:56.318179Z",
     "iopub.status.busy": "2026-03-06T11:31:56.287186Z",
     "iopub.status.idle": "2026-03-06T11:31:56.418024Z",
     "shell.execute_reply": "2026-03-06T11:31:56.416140Z"
    },
    "papermill": {
     "duration": 0.144183,
     "end_time": "2026-03-06T11:31:56.420580",
     "exception": false,
     "start_time": "2026-03-06T11:31:56.276397",
     "status": "completed"
    },
    "tags": []
   },
   "outputs": [],
   "source": [
    "# Generate daily dates from 2019-01-01 to 2024-12-31\n",
    "dates <- seq.Date(as.Date(\"2019-01-01\"), as.Date(\"2024-12-31\"), by = \"day\")\n",
    "n <- length(dates)\n",
    "\n",
    "# Create base tibble\n",
    "df <- tibble(\n",
    "  date = dates,\n",
    "  year = year(date),\n",
    "  month = month(date),\n",
    "  day_of_year = yday(date),\n",
    "  wday = wday(date, label = TRUE)\n",
    ")\n",
    "# Simulate demand, wind, solar with realistic patterns \n",
    "# Demand: annual cycle + weekly pattern + trend + noise\n",
    "df <- df %>%\n",
    "  mutate(\n",
    "    demand_base = 30000 + 5000 * sin(2 * pi * (day_of_year - 1) / 365 - pi/2),\n",
    "    weekly_effect = ifelse(wday %in% c(\"Sat\", \"Sun\"), -2000, 2000),\n",
    "    trend = 0.5 * (year - 2019) * 365 + day_of_year,\n",
    "    demand = demand_base + weekly_effect + trend/10 + rnorm(n, 0, 1200)\n",
    "  ) %>%\n",
    "  select(-demand_base, -weekly_effect, -trend)\n",
    "\n",
    "# Wind: more in winter, high variability, weekly pattern\n",
    "df <- df %>%\n",
    "  mutate(\n",
    "    wind_base = 8000 + 4000 * sin(2 * pi * (day_of_year - 1) / 365 - pi/2),\n",
    "    wind = pmax(0, wind_base + rnorm(n, 0, 2000) +\n",
    "                  2000 * sin(2 * pi * (day_of_year - 1) / 7))  # weekly component\n",
    "  ) %>%\n",
    "  select(-wind_base)\n",
    "\n",
    "# Solar: peak in summer\n",
    "df <- df %>%\n",
    "  mutate(\n",
    "    solar_base = 2000 + 2000 * sin(2 * pi * (day_of_year - 1) / 365),\n",
    "    solar = pmax(0, solar_base + rnorm(n, 0, 500) +\n",
    "                   1000 * (1 - 0.5 * sin(2 * pi * (day_of_year - 1) / 7)))\n",
    "  ) %>%\n",
    "  select(-solar_base)\n",
    "# Simulate price influenced by demand, wind, solar, shocks \n",
    "df <- df %>%\n",
    "  mutate(\n",
    "    # Linear relationship\n",
    "    price_linear = 30 + \n",
    "      0.0008 * demand - \n",
    "      0.0005 * wind - \n",
    "      0.0003 * solar,\n",
    "    # Seasonal effect (higher in winter)\n",
    "    seasonal_effect = 5 * sin(2 * pi * (day_of_year - 1) / 365 - pi/2),\n",
    "    # Random price spikes (approx 2% of days)\n",
    "    spike = ifelse(runif(n) < 0.02, runif(n, 50, 150), 0),\n",
    "    # Time‑varying volatility (more in winter)\n",
    "    vol_scale = 2 + 1.5 * sin(2 * pi * (day_of_year - 1) / 365 - pi/2),\n",
    "    error = rnorm(n, 0, vol_scale),\n",
    "    # Final price\n",
    "    price = price_linear + seasonal_effect + spike + error\n",
    "  ) %>%\n",
    "  select(date, year, month, day_of_year, wday, demand, wind, solar, price)\n",
    "\n",
    "# Introduce some missing values to demonstrate handling\n",
    "df$price[100:105] <- NA\n",
    "df$wind[300] <- NA\n"
   ]
  },
