   "source": [
    "# Interpolate missing values linearly (using zoo::na.approx)\n",
    "df <- df %>%\n",
    "  mutate(\n",
    "    price = na.approx(price, na.rm = FALSE),\n",
    "    wind = na.approx(wind, na.rm = FALSE),\n",
    "    solar = na.approx(solar, na.rm = FALSE),\n",
    "    demand = na.approx(demand, na.rm = FALSE)\n",
    "  ) %>%\n",
    "  # Drop any remaining NAs (first/last points if any)\n",
    "  drop_na()\n",
    "\n",
    "# Optional: log‑transform price to stabilise variance\n",
    "df <- df %>% mutate(log_price = log(price))\n",
    "\n",
    "# Create tsibble for time series operations\n",
    "df_ts <- df %>% as_tsibble(index = date)"
   ]
  },
