   ],
   "source": [
    "summary_stats <- df %>%\n",
    "  summarise(across(c(price, demand, wind, solar),\n",
    "                   list(mean = ~mean(.),\n",
    "                        sd = ~sd(.),\n",
    "                        min = ~min(.),\n",
    "                        max = ~max(.),\n",
    "                        skew = ~skewness(.),\n",
    "                        kurt = ~kurtosis(.)))) %>%\n",
    "  pivot_longer(everything(), names_to = c(\"variable\", \".value\"), names_sep = \"_\")\n",
    "print(summary_stats)"
   ]
  },
