   "source": [
    "p1 <- ggplot(df, aes(x = date, y = price)) +\n",
    "  geom_line(color = \"steelblue\") +\n",
    "  labs(title = \"Daily Electricity Price\", y = \"Price (£/MWh)\") +\n",
    "  theme_minimal()\n",
    "\n",
    "p2 <- ggplot(df, aes(x = date, y = demand)) +\n",
    "  geom_line(color = \"darkred\") +\n",
    "  labs(title = \"Electricity Demand\", y = \"Demand (MW)\") +\n",
    "  theme_minimal()\n",
    "\n",
    "p3 <- ggplot(df, aes(x = date, y = wind)) +\n",
    "  geom_line(color = \"darkgreen\") +\n",
    "  labs(title = \"Wind Generation\", y = \"Wind (MW)\") +\n",
    "  theme_minimal()\n",
    "\n",
    "p4 <- ggplot(df, aes(x = date, y = solar)) +\n",
    "  geom_line(color = \"orange\") +\n",
    "  labs(title = \"Solar Generation\", y = \"Solar (MW)\") +\n",
    "  theme_minimal()\n",
    "\n",
    "grid.arrange(p1, p2, p3, p4, ncol = 2)"
   ]
  },
