      "\n"
     ]
    }
   ],
   "source": [
    "df <- df %>%\n",
    "  arrange(date) %>%\n",
    "  mutate(\n",
    "    wind_lag1 = lag(wind),\n",
    "    solar_lag1 = lag(solar)\n",
    "  ) %>%\n",
    "  drop_na()  # drop first row with NA lags\n",
    "\n",
    "model2 <- lm(price ~ demand + wind + solar + wind_lag1 + solar_lag1, data = df)\n",
    "coeftest_model2 <- coeftest(model2, vcov = NeweyWest(model2, lag = 7))\n",
    "print(\"Model 2: Including Lagged Renewables\")\n",
    "print(coeftest_model2)"
   ]
  },
