    "xreg <- df[, c(\"demand\", \"wind\", \"solar\")]  # contemporary\n",
    "arimax_model <- auto.arima(df$price, xreg = as.matrix(xreg), seasonal = TRUE,\n",
    "                           stepwise = FALSE, approximation = FALSE)\n",
    "print(\"ARIMAX Model Summary:\")\n",
    "summary(arimax_model)"
   ]
