   "source": [
    "coef_arimax <- data.frame(\n",
    "  Coefficient = names(arimax_model$coef),\n",
    "  Estimate = arimax_model$coef,\n",
    "  `Std. Error` = sqrt(diag(vcov(arimax_model))),\n",
    "  `p-value` = 2 * (1 - pnorm(abs(arimax_model$coef / sqrt(diag(vcov(arimax_model))))))\n",
    ")\n",
    "print(coef_arimax)"
   ]
  },
