   "source": [
    "df <- df %>%\n",
    "  arrange(date) %>%\n",
    "  mutate(roll_sd_7 = zoo::rollapply(price, width = 7, FUN = sd, fill = NA, align = \"right\"),\n",
    "    roll_sd_30 = zoo::rollapply(price, width = 30, FUN = sd, fill = NA, align = \"right\"))\n",
    "# Plot rolling volatility\n",
    "ggplot(df, aes(x = date)) +\n",
    "  geom_line(aes(y = roll_sd_7, color = \"7-day SD\")) +\n",
    "  geom_line(aes(y = roll_sd_30, color = \"30-day SD\")) +\n",
    "  labs(title = \"Rolling Volatility of Electricity Price\",\n",
    "       y = \"Standard Deviation (£/MWh)\", color = \"Window\") +\n",
    "  theme_minimal()\n"
   ]
  },
