   "source": [
    "# Create daily log returns\n",
    "df <- df %>% arrange(date) %>% mutate(log_ret = c(NA, diff(log_price))) %>% drop_na()\n",
    "\n",
    "# Specify GARCH(1,1) with ARMA(1,1) mean (adjust as needed)\n",
    "spec <- ugarchspec(\n",
    "  variance.model = list(model = \"sGARCH\", garchOrder = c(1,1)),\n",
    "  mean.model = list(armaOrder = c(1,1), include.mean = TRUE),\n",
    "  distribution.model = \"norm\"\n",
    ")\n",
    "garch_fit <- ugarchfit(spec, data = df$log_ret, solver = \"hybrid\")\n",
    "print(\"GARCH(1,1) Model Summary:\")\n",
    "show(garch_fit)\n",
    "\n",
    "# Plot conditional volatility\n",
    "plot(garch_fit, which = 3)  # Conditional SD plot"
   ]
  },
