   "source": [
    "# Using strucchange::breakpoints (simple mean shift model)\n",
    "bp_test <- breakpoints(price ~ 1, data = df, h = 0.15)  # minimal segment 15% of observations\n",
    "summary(bp_test)\n",
    "# Plot BIC to choose number of breaks\n",
    "plot(bp_test)\n",
    "# Extract break dates (e.g., for 2 breaks)\n",
    "break_dates <- df$date[breakpoints(bp_test, breaks = 2)$breakpoints]\n",
    "print(paste(\"Potential break dates:\", break_dates))\n",
    "\n",
    "# Visualise breaks on price series\n",
    "ggplot(df, aes(x = date, y = price)) +\n",
    "  geom_line() +\n",
    "  geom_vline(xintercept = break_dates, linetype = \"dashed\", color = \"red\") +\n",
    "  labs(title = \"Electricity Price with Detected Structural Breaks\",\n",
    "       y = \"Price (£/MWh)\") +\n",
    "  theme_minimal()"
   ]
  },
