   "source": [
    "p_scatter_demand <- ggplot(df, aes(x = demand, y = price)) +\n",
    "  geom_point(alpha = 0.3) +\n",
    "  geom_smooth(method = \"lm\", se = FALSE, color = \"red\") +\n",
    "  labs(title = \"Price vs Demand\", x = \"Demand (MW)\", y = \"Price (£/MWh)\") +\n",
    "  theme_minimal()\n",
    "\n",
    "p_scatter_wind <- ggplot(df, aes(x = wind, y = price)) +\n",
    "  geom_point(alpha = 0.3) +\n",
    "  geom_smooth(method = \"lm\", se = FALSE, color = \"blue\") +\n",
    "  labs(title = \"Price vs Wind Generation\", x = \"Wind (MW)\", y = \"Price (£/MWh)\") +\n",
    "  theme_minimal()\n",
    "\n",
    "p_scatter_solar <- ggplot(df, aes(x = solar, y = price)) +\n",
    "  geom_point(alpha = 0.3) +\n",
    "  geom_smooth(method = \"lm\", se = FALSE, color = \"orange\") +\n",
    "  labs(title = \"Price vs Solar Generation\", x = \"Solar (MW)\", y = \"Price (£/MWh)\") +\n",
    "  theme_minimal()\n",
    "\n",
    "grid.arrange(p_scatter_demand, p_scatter_wind, p_scatter_solar, ncol = 3)\n"
   ]
  },
