   "source": [
    "df %>%\n",
    "  group_by(year, month) %>%\n",
    "  summarise(avg_price = mean(price), .groups = \"drop\") %>%\n",
    "  ggplot(aes(x = factor(month), y = factor(year), fill = avg_price)) +\n",
    "  geom_tile() +\n",
    "  scale_fill_gradient(low = \"yellow\", high = \"red\") +\n",
    "  labs(title = \"Average Monthly Price (£/MWh)\", x = \"Month\", y = \"Year\") +\n",
    "  theme_minimal()"
   ]
  },
