   "source": [
    "# Extract coefficients with robust standard errors\n",
    "coef_df <- data.frame(\n",
    "  term = names(coef(model1)),\n",
    "  estimate = coef(model1),\n",
    "  std_error = sqrt(diag(NeweyWest(model1, lag = 7)))\n",
    ") %>%\n",
    "  mutate(\n",
    "    lower = estimate - 1.96 * std_error,\n",
    "    upper = estimate + 1.96 * std_error\n",
    "  ) %>%\n",
    "  filter(term != \"(Intercept)\")  # exclude intercept\n",
    "\n",
    "ggplot(coef_df, aes(x = term, y = estimate)) +\n",
    "  geom_point(size = 3) +\n",
    "  geom_errorbar(aes(ymin = lower, ymax = upper), width = 0.2) +\n",
    "  geom_hline(yintercept = 0, linetype = \"dashed\") +\n",
    "  labs(title = \"Model 1 Coefficients with 95% Confidence Intervals\",\n",
    "       x = \"Variable\", y = \"Estimate\") +\n",
    "  theme_minimal()\n"
   ]
  },
